// Compile all data into a weekly report
const articles = $('Get This Week\'s Blog Articles').first().json.articles || [];
const orders = $('Get This Week\'s Orders').first().json.orders || [];
const sheetCsv = $('Get Blog Ideas Sheet').first().json.data || '';

// Count pending blog ideas in sheet
const sheetLines = sheetCsv.split('\n').filter(l => l.trim()).slice(1);
const DONE = ['drafted','published','done'];
let pendingIdeas = 0;
for (const line of sheetLines) {
  const cols = line.split(',');
  const status = (cols[4] || '').toLowerCase().trim();
  if (!DONE.includes(status) && cols[0]?.trim()) pendingIdeas++;
}

// Calculate order metrics
const totalRevenue = orders.reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0);
const publishedArticles = articles.filter(a => a.published_at);
const draftArticles = articles.filter(a => !a.published_at);

// Build the report
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const weekEnd = new Date();
const dateRange = `${weekStart.toLocaleDateString('en-US', {month:'short',day:'numeric'})} - ${weekEnd.toLocaleDateString('en-US', {month:'short',day:'numeric',year:'numeric'})}`;

const report = `
🌙 WAX & WANE WEEKLY REPORT
${dateRange}
${'='.repeat(40)}

📝 CONTENT
• Blog drafts created this week: ${articles.length}
• Published: ${publishedArticles.length}
• Pending review (drafts): ${draftArticles.length}
• Blog ideas still in queue: ${pendingIdeas}

${draftArticles.length > 0 ? '📋 DRAFTS READY TO PUBLISH:\n' + draftArticles.map(a => `  • ${a.title}`).join('\n') + '\n' : ''}
💰 SALES
• Orders this week: ${orders.length}
• Revenue: $${totalRevenue.toFixed(2)}

📅 UPCOMING
• Next blog run: This Sunday & Thursday at 2:00 PM
• Next catalog sync: Next Monday at 6:00 AM

${'='.repeat(40)}
View your store: https://waxandwane.store
Shopify admin: https://admin.shopify.com/store/6f97d0
`;

return [{ json: { report, articles_count: articles.length, orders_count: orders.length, revenue: totalRevenue.toFixed(2), pending_ideas: pendingIdeas } }];

// Log the report to n8n execution log
const report = $input.first().json.report;
console.log(report);
return [{ json: { success: true, report_sent: true, timestamp: new Date().toISOString() } }];
